const sbHeaders = {
  "Content-Type": "application/json",
  "apikey": SB_KEY,
  "Authorization": `Bearer ${SB_KEY}`,
  "Prefer": "return=representation",
};

async function sbGet(key) {
  try {
    const r = await fetch(`${SB_URL}/rest/v1/proyectos?id=eq.${encodeURIComponent(key)}&select=data`, { headers: sbHeaders });
    const data = await r.json();
    return data?.[0]?.data ?? null;
  } catch(e) { return null; }
}

async function sbSet(key, value) {
  try {
    await fetch(`${SB_URL}/rest/v1/proyectos`, {
      method: "POST",
      headers: { ...sbHeaders, "Prefer": "resolution=merge-duplicates,return=minimal" },
      body: JSON.stringify({ id: key, data: value, updated_at: new Date().toISOString() })
    });
  } catch(e) { console.error("sbSet error", e); }
}


