            <button onClick={guardarEdicion} style={{ flex:2, padding:"11px", background:`linear-gradient(135deg,${C.verde},${C.azul})`, border:"none", borderRadius:8, color:"#fff", fontWeight:700, cursor:"pointer" }}>Guardar cambios</button>
