                    <span key={i} style={{ background:`${n.color}15`, color:n.color, padding:"5px 12px", borderRadius:6, fontSize:12, fontWeight:700 }}>{[0,21,41,61,81][i]}–{[20,40,60,80,100][i]}% · {n.label}</span>
